def findMinSumSubarray(n, k, arr):
    current_sum = sum(arr[:k])
    min_sum = current_sum

    for i in range(k, n):
        current_sum += arr[i] - arr[i - k]
        if current_sum < min_sum:
            min_sum = current_sum

    return min_sum

